import{_ as o,C as n,o as d,c as h,j as a,a as e,E as r,a2 as i}from"./chunks/framework.BnBoz4Zl.js";const k=JSON.parse('{"title":"课外阅读：一章看懂 AI 工作系统","description":"这张图可以用一句话解释：模型负责理解和生成，Agent 负责围绕目标组织行动，Skill 提供专业方法，工具与 MCP/API 让行动触达真实世界，人负责边界与验收。 把一次真实任务拆开看，信息大致这样流动：","frontmatter":{},"headers":[],"relativePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/课外阅读：一章看懂 AI 工作系统/index.md","filePath":"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/课外阅读：一章看懂 AI 工作系统/index.md","lastUpdated":1783659790000}'),s={name:"bluebook/第一篇 使用手册：先把 WorkBuddy 用起来/课外阅读：一章看懂 AI 工作系统/index.md"};function p(A,t,E,g,u,c){const l=n("MermaidDiagram");return d(),h("div",null,[t[0]||(t[0]=a("h1",{id:"课外阅读-一章看懂-ai-工作系统",tabindex:"-1"},[e("课外阅读：一章看懂 AI 工作系统 "),a("a",{class:"header-anchor",href:"#课外阅读-一章看懂-ai-工作系统","aria-label":'Permalink to "课外阅读：一章看懂 AI 工作系统"'},"​")],-1)),t[1]||(t[1]=a("h2",{id:"先看全景-一次-ai-任务里发生了什么",tabindex:"-1"},[e("先看全景：一次 AI 任务里发生了什么 "),a("a",{class:"header-anchor",href:"#先看全景-一次-ai-任务里发生了什么","aria-label":'Permalink to "先看全景：一次 AI 任务里发生了什么"'},"​")],-1)),r(l,{graph:"flowchart%20LR%0A%20%20%20%20U%5B%E7%94%A8%E6%88%B7%E7%9B%AE%E6%A0%87%E4%B8%8E%E8%B5%84%E6%96%99%5D%20--%3E%20A%5BAgent%20%E8%A7%84%E5%88%92%5D%0A%20%20%20%20A%20--%3E%20L%5BLLM%20%E7%90%86%E8%A7%A3%E4%B8%8E%E7%94%9F%E6%88%90%5D%0A%20%20%20%20A%20--%3E%20S%5BSkill%20%E6%96%B9%E6%B3%95%E4%B8%8E%E8%84%9A%E6%9C%AC%5D%0A%20%20%20%20A%20--%3E%20T%5BTool%20%2F%20Connector%5D%0A%20%20%20%20T%20--%3E%20M%5BMCP%20%2F%20API%5D%0A%20%20%20%20M%20--%3E%20X%5B%E6%96%87%E4%BB%B6%E3%80%81%E7%9F%A5%E8%AF%86%E5%BA%93%E4%B8%8E%E4%B8%9A%E5%8A%A1%E7%B3%BB%E7%BB%9F%5D%0A%20%20%20%20L%20--%3E%20R%5B%E4%B8%AD%E9%97%B4%E7%BB%93%E6%9E%9C%5D%0A%20%20%20%20S%20--%3E%20R%0A%20%20%20%20X%20--%3E%20R%0A%20%20%20%20R%20--%3E%20C%5B%E6%A3%80%E6%9F%A5%E7%82%B9%E4%B8%8E%E9%AA%8C%E6%94%B6%5D%0A%20%20%20%20C%20--%3E%20O%5B%E6%9C%80%E7%BB%88%E4%BA%A7%E7%89%A9%5D%0A"}),t[2]||(t[2]=i('<p>这张图可以用一句话解释：<strong>模型负责理解和生成，Agent 负责围绕目标组织行动，Skill 提供专业方法，工具与 MCP/API 让行动触达真实世界，人负责边界与验收。</strong></p><p>把一次真实任务拆开看，信息大致这样流动：</p><p>你提出一个目标 → Agent 把它拆成几步 → 遇到专业子任务就加载对应的 Skill，遇到要碰外部系统就调用工具 → 工具通过 MCP 或 API 真正读写数据库、发消息、改文件 → 结果回到模型，模型判断下一步 → 你做边界把控和最终验收。</p><p>五类角色里，<strong>模型是大脑，Agent 是调度员，Skill 是专家手册，工具与接口是手脚，人是裁判</strong>。后面每一节就是把其中一个角色讲清楚，顺便标出它能和不能的边界。</p><h2 id="llm-会根据上下文预测内容的基础模型" tabindex="-1">LLM：会根据上下文预测内容的基础模型 <a class="header-anchor" href="#llm-会根据上下文预测内容的基础模型" aria-label="Permalink to &quot;LLM：会根据上下文预测内容的基础模型&quot;">​</a></h2><p>LLM 是 Large Language Model，大语言模型。它从大量数据中学习语言和知识模式，根据当前输入生成最可能的后续内容。</p><p>它本质上是个「预测下一个内容」的引擎，不是数据库，也不是会替你负责的人。</p><h3 id="它擅长什么" tabindex="-1">它擅长什么 <a class="header-anchor" href="#它擅长什么" aria-label="Permalink to &quot;它擅长什么&quot;">​</a></h3><ul><li>理解、归纳和改写文本；</li><li>从材料中提取结构；</li><li>生成草稿、方案和代码；</li><li>根据示例模仿格式和风格；</li><li>在工具返回结果后继续分析。</li></ul><h3 id="它不天然保证什么" tabindex="-1">它不天然保证什么 <a class="header-anchor" href="#它不天然保证什么" aria-label="Permalink to &quot;它不天然保证什么&quot;">​</a></h3><ul><li>不保证每个事实都正确；</li><li>不知道企业最新内部状态，除非提供资料或连接系统；</li><li>不会因为语言自信就拥有真实证据；</li><li>不自动拥有文件、账号、数据库和网络权限；</li><li>不承担业务和法律责任。</li></ul><h3 id="为什么会「幻觉」" tabindex="-1">为什么会「幻觉」 <a class="header-anchor" href="#为什么会「幻觉」" aria-label="Permalink to &quot;为什么会「幻觉」&quot;">​</a></h3><p>模型的目标是生成连贯内容，不是内置事实数据库。当资料缺失、问题含糊或要求它给出确定答案时，它可能用合理但不真实的内容填补空白。</p><p>这不是 bug，是「按概率补全」这件事的副作用。理解了这点，你就不会再追问「它明明说得很肯定，为什么是错的」——肯定和正确是两件事。</p><h3 id="降低幻觉的办法" tabindex="-1">降低幻觉的办法 <a class="header-anchor" href="#降低幻觉的办法" aria-label="Permalink to &quot;降低幻觉的办法&quot;">​</a></h3><ul><li>提供可靠资料；</li><li>要求引用位置（说清楚结论来自哪段材料）；</li><li>允许回答「无法确认」；</li><li>把事实提取与建议生成分开；</li><li>对高影响结论人工复核。</li></ul><h2 id="token-与上下文窗口-模型眼前能看到多少" tabindex="-1">Token 与上下文窗口：模型眼前能看到多少 <a class="header-anchor" href="#token-与上下文窗口-模型眼前能看到多少" aria-label="Permalink to &quot;Token 与上下文窗口：模型眼前能看到多少&quot;">​</a></h2><p>Token 是模型处理文本的基本单位，不完全等于字数。中文里一个字可能对应一个或几个 Token，代码和标点也单独计费。上下文窗口是一次推理中模型能够处理的输入、历史对话和输出总量。</p><p>把 Token 想成模型的短期记忆容量：装得下才看得见，装不下就得丢或压缩。</p><h3 id="上下文变长不一定更好" tabindex="-1">上下文变长不一定更好 <a class="header-anchor" href="#上下文变长不一定更好" aria-label="Permalink to &quot;上下文变长不一定更好&quot;">​</a></h3><p>把所有文件和几个月对话都塞进一个任务，可能导致：</p><ul><li>旧要求与新要求冲突；</li><li>关键资料被大量无关内容淹没；</li><li>成本和等待时间增加；</li><li>模型引用了过期版本。</li></ul><p>窗口越大，越容易「水漫金山」——重要的反而被冲淡。</p><h3 id="更稳妥的做法" tabindex="-1">更稳妥的做法 <a class="header-anchor" href="#更稳妥的做法" aria-label="Permalink to &quot;更稳妥的做法&quot;">​</a></h3><p>按项目整理「当前规则、已确认事实、决策记录和本次输入」，长项目使用文件和项目记忆，而不是依赖无限对话。</p><p>简单说：<strong>别把所有聊天记录当数据库用</strong>，该落盘的落盘，该分项目的分开。</p><h2 id="prompt-任务说明-不是神秘咒语" tabindex="-1">Prompt：任务说明，不是神秘咒语 <a class="header-anchor" href="#prompt-任务说明-不是神秘咒语" aria-label="Permalink to &quot;Prompt：任务说明，不是神秘咒语&quot;">​</a></h2><p>Prompt 是给模型或 Agent 的输入，包括目标、背景、资料、约束、示例和输出要求。好的 Prompt 不以长度取胜，而以信息是否足够执行和验收取胜。</p><p>写 Prompt 不是在「念咒」，是在写一份能交给同事执行的任务单。</p><h3 id="六要素" tabindex="-1">六要素 <a class="header-anchor" href="#六要素" aria-label="Permalink to &quot;六要素&quot;">​</a></h3><table tabindex="0"><thead><tr><th>要素</th><th>要回答的问题</th></tr></thead><tbody><tr><td>目标</td><td>最终解决什么问题</td></tr><tr><td>输入</td><td>使用哪些资料或系统</td></tr><tr><td>动作</td><td>分析、整理、生成还是写入</td></tr><tr><td>约束</td><td>不能做什么，采用什么规则</td></tr><tr><td>输出</td><td>交付什么文件或结构</td></tr><tr><td>验收</td><td>怎样判断正确和可用</td></tr></tbody></table><p>六要素里最容易被忽略的是「验收」：没有验收标准，模型只能按自己的理解交差，你也就没法说它错在哪。</p><h3 id="prompt、任务卡与-sop" tabindex="-1">Prompt、任务卡与 SOP <a class="header-anchor" href="#prompt、任务卡与-sop" aria-label="Permalink to &quot;Prompt、任务卡与 SOP&quot;">​</a></h3><ul><li><strong>Prompt</strong>：本次怎么说；</li><li><strong>任务卡</strong>：同类任务可以填写的结构；</li><li><strong>SOP</strong>：固定步骤、角色、检查点和异常处理；</li><li><strong>Skill</strong>：把稳定 SOP、脚本和资源封装成可执行能力。</li></ul><p>四者是从「一次性说明」到「可复用能力」的逐级固化。</p><p><strong>不是每个 Prompt 都值得变成 Skill。</strong> 先重复成功，再逐步固化。一个只做过一次的任务，先写好 Prompt 跑通；跑顺三五次、模式稳定了，再考虑沉淀成 Skill。</p><h2 id="agent-能围绕目标循环行动的执行体" tabindex="-1">Agent：能围绕目标循环行动的执行体 <a class="header-anchor" href="#agent-能围绕目标循环行动的执行体" aria-label="Permalink to &quot;Agent：能围绕目标循环行动的执行体&quot;">​</a></h2><p>Agent 不只是「回答一次」，而是持续执行一个循环：<strong>理解目标、观察环境、决定下一步、调用工具、读取结果、修正计划，直到交付或触发停止条件。</strong></p>',38)),r(l,{graph:"flowchart%20TD%0A%20%20%20%20A%5B%E6%8E%A5%E6%94%B6%E7%9B%AE%E6%A0%87%5D%20--%3E%20B%5B%E8%A7%82%E5%AF%9F%E8%B5%84%E6%96%99%E4%B8%8E%E7%8A%B6%E6%80%81%5D%0A%20%20%20%20B%20--%3E%20C%5B%E8%A7%84%E5%88%92%E4%B8%8B%E4%B8%80%E6%AD%A5%5D%0A%20%20%20%20C%20--%3E%20D%5B%E8%B0%83%E7%94%A8%E5%B7%A5%E5%85%B7%E6%89%A7%E8%A1%8C%5D%0A%20%20%20%20D%20--%3E%20E%5B%E8%AF%BB%E5%8F%96%E7%BB%93%E6%9E%9C%E4%B8%8E%E9%94%99%E8%AF%AF%5D%0A%20%20%20%20E%20--%3E%20F%7B%E5%AE%8C%E6%88%90%E6%88%96%E5%BA%94%E6%9A%82%E5%81%9C%EF%BC%9F%7D%0A%20%20%20%20F%20--%3E%7C%E7%BB%A7%E7%BB%AD%7C%20B%0A%20%20%20%20F%20--%3E%7C%E6%9A%82%E5%81%9C%7C%20G%5B%E8%AF%B7%E6%B1%82%E4%BA%BA%E5%B7%A5%E7%A1%AE%E8%AE%A4%5D%0A%20%20%20%20F%20--%3E%7C%E5%AE%8C%E6%88%90%7C%20H%5B%E4%BA%A4%E4%BB%98%E5%B9%B6%E9%AA%8C%E6%94%B6%5D%0A"}),t[3]||(t[3]=i(`<p>聊天模型是「你问一句它答一句」；Agent 是「你给目标，它自己一步步推进，中途还会看结果、改路线」。</p><h3 id="agent-与聊天模型的区别" tabindex="-1">Agent 与聊天模型的区别 <a class="header-anchor" href="#agent-与聊天模型的区别" aria-label="Permalink to &quot;Agent 与聊天模型的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>聊天模型</th><th>Agent</th></tr></thead><tbody><tr><td>核心动作</td><td>生成回答</td><td>规划、调用工具、执行和交付</td></tr><tr><td>工作对象</td><td>当前对话</td><td>文件、工具、系统和任务状态</td></tr><tr><td>过程</td><td>通常一次生成</td><td>多轮观察与行动</td></tr><tr><td>风险</td><td>内容错误</td><td>内容错误 + 真实操作影响</td></tr><tr><td>控制</td><td>提示与复核</td><td>权限、检查点、日志和回滚</td></tr></tbody></table><p>关键差异在最后一行：聊天模型说错了，最多误导你；Agent 做错了，可能真的删了文件、发了邮件、改了数据库。所以 Agent 需要的不是更聪明的提示，而是更硬的护栏。</p><h3 id="agent-的停止条件" tabindex="-1">Agent 的停止条件 <a class="header-anchor" href="#agent-的停止条件" aria-label="Permalink to &quot;Agent 的停止条件&quot;">​</a></h3><p>好的 Agent 不应「永远想办法继续」。出现以下情况，应暂停并请求人处理：</p><ul><li>关键输入缺失；</li><li>目标冲突；</li><li>权限不足；</li><li>成本超预算；</li><li>动作不可逆；</li><li>结果无法验收。</li></ul><p>知道什么时候停下来问人比 什么都自己硬扛 更专业。一个不会停的 Agent，比一个笨 Agent 更危险。</p><h2 id="tool-让-agent-真的能做事" tabindex="-1">Tool ：让 Agent 真的能做事 <a class="header-anchor" href="#tool-让-agent-真的能做事" aria-label="Permalink to &quot;Tool ：让 Agent 真的能做事&quot;">​</a></h2><p>Tool 是 Agent 可以调用的具体能力，例如读取文件、执行搜索、生成表格或发送消息。Connector 通常是产品已经封装好的第三方服务连接，强调授权后直接使用。</p><h3 id="模型知道不等于模型能做" tabindex="-1">模型知道不等于模型能做 <a class="header-anchor" href="#模型知道不等于模型能做" aria-label="Permalink to &quot;模型知道不等于模型能做&quot;">​</a></h3><p>模型可以解释「如何发送邮件」，但只有获得邮件工具和账号权限后才能实际创建草稿或发送。模型可以写 SQL，但只有数据库工具、网络和账号允许时才能查询。</p><p>这点是普通用户最容易误解的：<strong>模型「懂」一件事，不代表它「能」做这件事。</strong> 能不能做，取决于有没有对应的工具、权限和连接。任务失败时，先问「工具通没通、权限给没给」，而不是「模型是不是不行」。</p><h3 id="每个工具要问五件事" tabindex="-1">每个工具要问五件事 <a class="header-anchor" href="#每个工具要问五件事" aria-label="Permalink to &quot;每个工具要问五件事&quot;">​</a></h3><ol><li>使用谁的身份；</li><li>能读取什么；</li><li>能修改什么；</li><li>数据会发到哪里；</li><li>失败后如何停止和回退。</li></ol><h2 id="skill-可复用的专业工作方法" tabindex="-1">Skill：可复用的专业工作方法 <a class="header-anchor" href="#skill-可复用的专业工作方法" aria-label="Permalink to &quot;Skill：可复用的专业工作方法&quot;">​</a></h2><p>Skill 不是更聪明的模型，而是把某类任务需要的说明、脚本、知识和模板组织起来，让 Agent 更稳定地完成动作。</p><p>Skill 的价值不在「让模型变强」，而在「把容易做错、容易遗漏的环节固定下来」。同样的发票处理，让模型每次现写，十次可能有三种写法；写成 Skill，十次走同一条被验证过的路。</p><h3 id="一个-skill-可能包含" tabindex="-1">一个 Skill 可能包含 <a class="header-anchor" href="#一个-skill-可能包含" aria-label="Permalink to &quot;一个 Skill 可能包含&quot;">​</a></h3><div class="language-Plain vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">Plain</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>invoice-skill/</span></span>
<span class="line"><span>├── SKILL.md          # 触发条件、步骤、边界与输出</span></span>
<span class="line"><span>├── references/       # 字段、分类和业务规则</span></span>
<span class="line"><span>├── scripts/          # OCR、校验、表格处理</span></span>
<span class="line"><span>├── templates/        # Excel 和报告模板</span></span>
<span class="line"><span>└── tests/            # 正常与异常样例</span></span></code></pre></div><p>SKILL.md 是入口，告诉 Agent「什么时候用我、怎么用、边界在哪」；references 放业务知识；scripts 放真正执行的代码；templates 保证输出格式一致；tests 保证异常情况也被覆盖。</p><h3 id="skill-与-prompt-的区别" tabindex="-1">Skill 与 Prompt 的区别 <a class="header-anchor" href="#skill-与-prompt-的区别" aria-label="Permalink to &quot;Skill 与 Prompt 的区别&quot;">​</a></h3><p>Prompt 往往只影响本次对话；Skill 可以被不同任务调用，并能携带脚本、资源和稳定流程。但 Skill 仍可能出错，也可能请求本地、网络或第三方权限。</p><p>记住：<strong>Skill 是「方法封装」，不是「能力保证」。</strong> 装了 Skill，Agent 更可能走对路，但不等于永远不会出错。</p><h3 id="安装第三方-skill-的风险" tabindex="-1">安装第三方 Skill 的风险 <a class="header-anchor" href="#安装第三方-skill-的风险" aria-label="Permalink to &quot;安装第三方 Skill 的风险&quot;">​</a></h3><ul><li>读取不必要的本地目录；</li><li>外发输入材料；</li><li>获取 API Key 或账号；</li><li>执行系统命令；</li><li>包含恶意提示或代码；</li><li>依赖过期、无人维护。</li></ul><p>因此应检查来源、代码、权限、网络、凭证、成本和停用方法，并先在隔离目录测试。第三方 Skill 和装浏览器插件一个道理：方便，但要先看它要什么权限。</p><h2 id="mcp-让-ai-接入工具与数据的标准接口" tabindex="-1">MCP：让 AI 接入工具与数据的标准接口 <a class="header-anchor" href="#mcp-让-ai-接入工具与数据的标准接口" aria-label="Permalink to &quot;MCP：让 AI 接入工具与数据的标准接口&quot;">​</a></h2><p>MCP 是 Model Context Protocol。它规定 AI 客户端如何发现和调用外部工具、读取资源或获取提示模板，可以理解为 AI 工具生态的一类标准接口。</p><p>把 MCP 想成「AI 世界的 USB 接口」：工具提供方按一套标准暴露能力，AI 客户端按同一套标准去用，不用每家重新适配。</p><h3 id="mcp-解决什么" tabindex="-1">MCP 解决什么 <a class="header-anchor" href="#mcp-解决什么" aria-label="Permalink to &quot;MCP 解决什么&quot;">​</a></h3><p>如果每个 AI 产品都要为每个系统开发一套专用连接，集成成本很高。MCP 让工具提供方和 AI 客户端按统一方式描述能力，降低重复适配。</p><p>没有 MCP 时，接一个 CRM 要写一套适配，接一个数据库又写一套；有了 MCP，工具方一次性按标准暴露，所有支持 MCP 的客户端都能直接用。</p><h3 id="mcp-不解决什么" tabindex="-1">MCP 不解决什么 <a class="header-anchor" href="#mcp-不解决什么" aria-label="Permalink to &quot;MCP 不解决什么&quot;">​</a></h3><ul><li>不自动判断数据是否合规；</li><li>不替你保管好所有密钥；</li><li>不保证工具结果正确；</li><li>不自动实现身份与最小权限；</li><li>不等于连接后可以开放生产写入。</li></ul><p>MCP 解决的是「怎么连」，不解决「连了之后安不安全、对不对」。安全那层仍然是你的责任。</p><h3 id="用户级与项目级" tabindex="-1">用户级与项目级 <a class="header-anchor" href="#用户级与项目级" aria-label="Permalink to &quot;用户级与项目级&quot;">​</a></h3><ul><li><strong>用户级</strong>适合多个项目复用的公共能力；</li><li><strong>项目级</strong>适合客户、数据库或业务专属工具。</li></ul><p>敏感连接优先项目隔离，避免跨项目误调用。比如公司的生产数据库，只该在对应项目里接，别放成全局用户级，否则另一个无关任务也可能摸到它。</p><h2 id="api-与-mcp-的关系" tabindex="-1">API 与 MCP 的关系 <a class="header-anchor" href="#api-与-mcp-的关系" aria-label="Permalink to &quot;API 与 MCP 的关系&quot;">​</a></h2><p>API 是软件之间交互的接口，例如通过 HTTP 查询数据或创建记录。MCP Server 可以在内部调用一个或多个 API，再以 Agent 更容易使用的方式暴露工具。</p><p>一句话：<strong>API 是地基，MCP 是在地基上盖的、Agent 能直接进出的门。</strong> Agent 通常不直接跟一堆原始 API 打交道，而是通过一个 MCP Server 间接调用它们。</p><h3 id="直接用-api-还是用-mcp" tabindex="-1">直接用 API 还是用 MCP <a class="header-anchor" href="#直接用-api-还是用-mcp" aria-label="Permalink to &quot;直接用 API 还是用 MCP&quot;">​</a></h3><ul><li><strong>直接使用 API</strong> 更灵活，但需要理解认证、参数、错误和限流；</li><li><strong>使用成熟 MCP</strong> 更方便，但仍要审查它封装了什么请求和权限。</li></ul><p>方便不等于免审。MCP 帮你省了适配活，但「它背后到底调了什么 API、用了什么权限」你得心里有数。</p><h2 id="知识库、rag-与记忆" tabindex="-1">知识库、RAG 与记忆 <a class="header-anchor" href="#知识库、rag-与记忆" aria-label="Permalink to &quot;知识库、RAG 与记忆&quot;">​</a></h2><p>这三者都和「AI 依据什么」有关，但保存的东西和失效方式完全不同。</p><h3 id="知识库" tabindex="-1">知识库 <a class="header-anchor" href="#知识库" aria-label="Permalink to &quot;知识库&quot;">​</a></h3><p>保存可检索的制度、产品、案例、SOP 和其他资料。它解决「AI 依据什么」，不等于 AI 永远记住一切。</p><p>知识库是external 的资料室，模型用时才去翻，翻完不保证下次还记。</p><h3 id="rag" tabindex="-1">RAG <a class="header-anchor" href="#rag" aria-label="Permalink to &quot;RAG&quot;">​</a></h3><p>RAG 是 Retrieval-Augmented Generation，检索增强生成。系统先从资料库找到相关片段，再把片段提供给模型回答。效果取决于资料质量、分段、元数据、检索和引用。</p><p>RAG 不是「接了知识库就聪明」，它是一根链条：资料差、切得烂、检索偏，回答就跟着歪。引用机制很重要——能指出结论来自哪段，你才能判断信不信。</p><h3 id="记忆" tabindex="-1">记忆 <a class="header-anchor" href="#记忆" aria-label="Permalink to &quot;记忆&quot;">​</a></h3><p>记忆用于保存偏好、长期规则、项目决策或历史状态。错误记忆会被反复放大，因此重要信息要有来源、日期、负责人和更新机制。</p><p>记忆最危险的地方是「它自己不会发现过期」。一条半年前的错误规则，会被 Agent 当真理反复用。</p><h3 id="三者的区别" tabindex="-1">三者的区别 <a class="header-anchor" href="#三者的区别" aria-label="Permalink to &quot;三者的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>保存什么</th><th>主要风险</th></tr></thead><tbody><tr><td>对话上下文</td><td>当前任务交流</td><td>太长、冲突、过期</td></tr><tr><td>知识库 / RAG</td><td>可检索事实与资料</td><td>来源差、版本旧、检索不到</td></tr><tr><td>记忆</td><td>偏好、长期规则、项目状态</td><td>错误被长期沿用</td></tr></tbody></table><p>一句话区分：<strong>上下文是这次聊天的短期记忆，知识库是随时可查的资料室，记忆是跨任务保留的长期设定。</strong></p><h2 id="workflow-与-agent-的区别" tabindex="-1">Workflow 与 Agent 的区别 <a class="header-anchor" href="#workflow-与-agent-的区别" aria-label="Permalink to &quot;Workflow 与 Agent 的区别&quot;">​</a></h2><p>前面把 Agent 讲清楚了，但还有一个常被混用的词：<strong>Workflow（工作流）</strong>。它和 Agent 不是替代关系，而是两种「组织行动」的思路。</p><h3 id="一句话区分" tabindex="-1">一句话区分 <a class="header-anchor" href="#一句话区分" aria-label="Permalink to &quot;一句话区分&quot;">​</a></h3><ul><li><strong>Workflow 是标准化的生产线</strong>：步骤在设计时就定好，按顺序或分支执行。</li><li><strong>Agent 是会思考、能自己拿主意的执行者</strong>：只给目标，运行时自己决定下一步怎么走。</li></ul><p>打个比方，Workflow 像一份写了「第一步做 A，第二步做 B，B 通过后做 C 否则做 D」的 SOP；Agent 像你雇的一个人，你只说「把这批发票处理完」，他中途自己判断要先查哪张、卡住了问你。</p><h3 id="核心区别-决策权在哪" tabindex="-1">核心区别：决策权在哪 <a class="header-anchor" href="#核心区别-决策权在哪" aria-label="Permalink to &quot;核心区别：决策权在哪&quot;">​</a></h3><p>Workflow 的每一步「走哪条路」在设计阶段就固定了；Agent 的下一步由模型在执行阶段根据环境实时决定。这是两者最本质的差别，其他差别都从这儿长出来。</p><h3 id="对比表" tabindex="-1">对比表 <a class="header-anchor" href="#对比表" aria-label="Permalink to &quot;对比表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>Workflow（工作流）</th><th>Agent（智能体）</th></tr></thead><tbody><tr><td>一句话</td><td>标准化的生产线</td><td>会思考、能自己拿主意的执行者</td></tr><tr><td>路径是否预设</td><td>是，步骤在设计时定好</td><td>否，运行时根据环境决定</td></tr><tr><td>决策时机</td><td>设计阶段固定</td><td>执行阶段动态</td></tr><tr><td>谁来选下一步</td><td>流程定义</td><td>模型自己</td></tr><tr><td>可控性</td><td>高，容易预测和回滚</td><td>较低，路径可能变化</td></tr><tr><td>调试难度</td><td>低，步骤清晰可追</td><td>高，需看日志和中间状态</td></tr><tr><td>适用场景</td><td>步骤明确、可重复、合规要求高</td><td>路径不确定、需环境反馈、开放目标</td></tr><tr><td>典型失败</td><td>卡在某步、分支没覆盖</td><td>跑偏、无限循环、越权操作</td></tr><tr><td>与 LLM 关系</td><td>管道里可嵌入模型，但控制流是人定的</td><td>模型驱动控制流</td></tr></tbody></table><h3 id="什么时候用-workflow" tabindex="-1">什么时候用 Workflow <a class="header-anchor" href="#什么时候用-workflow" aria-label="Permalink to &quot;什么时候用 Workflow&quot;">​</a></h3><ul><li>固定 SOP，比如「收到工单 → 分类 → 派给对应人」；</li><li>批量处理，比如「把 100 张图统一压缩加水印」；</li><li>合规审批，每一步都要留痕、可审计；</li><li>可重复的报表生成。</li></ul><p>这些任务路径清楚，用 Workflow 更稳、更便宜、更好查。</p><h3 id="什么时候用-agent" tabindex="-1">什么时候用 Agent <a class="header-anchor" href="#什么时候用-agent" aria-label="Permalink to &quot;什么时候用 Agent&quot;">​</a></h3><ul><li>目标清楚但路径不清，比如「调研竞品并出对比报告」；</li><li>需要多工具探索、中途看结果再决定；</li><li>环境会变，需要边做边调整；</li><li>开放性强、难以写成固定步骤的任务。</li></ul><h3 id="常见误区" tabindex="-1">常见误区 <a class="header-anchor" href="#常见误区" aria-label="Permalink to &quot;常见误区&quot;">​</a></h3><ul><li><strong>「Agent 一定比 Workflow 强」</strong>：不对。确定任务用 Workflow 更稳更省，硬上 Agent 反而容易跑偏、难审计、成本高。</li><li><strong>「Workflow 不能含智能」</strong>：错。Workflow 的节点完全可以调用模型做摘要、分类、抽取，只是「走哪条路」仍由流程定。</li><li><strong>「Agent 全自动就最好」</strong>：过度放权会让失败更难定位。真复杂的系统，往往是 Agent 在高层决策，把稳定环节交给 Workflow。</li></ul><h3 id="两者如何协同" tabindex="-1">两者如何协同 <a class="header-anchor" href="#两者如何协同" aria-label="Permalink to &quot;两者如何协同&quot;">​</a></h3><p>不是二选一，而是嵌套使用：</p><ul><li><strong>Agent 内含 Workflow</strong>：Agent 把已经稳定的子任务写成固定流程（比如一个 Skill 背后就是 Workflow），只在不确定处自己判断；</li><li><strong>Workflow 节点调 Agent</strong>：生产线上某个判断节点，交给一个 Agent 处理非结构化输入。</li></ul>`,78))])}const P=o(s,[["render",p]]);export{k as __pageData,P as default};
